private navigateIfNeeded(
  routerStoreState: RouterReducerState,
  storeState: any
): void {
  if (!routerStoreState || !routerStoreState.state) {
    return;
  }
  if (this.trigger === RouterTrigger.ROUTER) {
    return;
  }
  if (this.lastEvent instanceof NavigationStart) {
    return;
  }

  const url = routerStoreState.state.url;
  if (!isSameUrl(this.router.url, url)) {
    this.storeState = storeState;
    this.trigger = RouterTrigger.STORE;
    this.router.navigateByUrl(url).catch((error) => {
      this.errorHandler.handleError(error);
    });
  }
}

private dispatchRouterAction(
  type: string,
  payload: StoreRouterActionPayload
): void {
  this.trigger = RouterTrigger.ROUTER;
  try {
    this.store.dispatch({
      type,
      payload: {
        routerState: this.routerState,
        ...payload,
        event:
          this.config.routerState === RouterState.Full
            ? payload.event
            : {
                id: payload.event.id,
                url: payload.event.url,
                // safe, as it will just be `undefined` for non-NavigationEnd router events
                urlAfterRedirects: (payload.event as NavigationEnd)
                  .urlAfterRedirects,
              },
      },
    });
  } finally {
    this.trigger = RouterTrigger.NONE;
  }
}

resolveFieldTypeRef(field: FormlyFieldConfigCache = {}): ComponentRef<FieldType> {
  const type: TypeOption = this.getType(field.type);
  if (!type) {
    return null;
  }

  if (!type.component) {
    return null;
  }

  if (!this.componentRefs[type.name]) {
    const { _viewContainerRef, _injector } = field.options;
    if (!_viewContainerRef || !_injector) {
      return null;
    }

    const componentRef = _viewContainerRef.createComponent<FieldType>(type.component, { injector: _injector });
    this.componentRefs[type.name] = componentRef;
    try {
      componentRef.destroy();
    } catch (e) {
      console.error(`An error occurred while destroying the Formly component type "${field.type}"`, e);
    }
  }

  return this.componentRefs[type.name];
}

private getFieldComponentInstance(field: FormlyFieldConfigCache) {
  const componentRefInstance = () => {
    let componentRef = this.config.resolveFieldTypeRef(field);

    const fieldComponentRef = field._componentRefs?.slice(-1)[0];
    if (
      fieldComponentRef instanceof ComponentRef &&
      fieldComponentRef?.componentType === componentRef?.componentType
    ) {
      componentRef = fieldComponentRef as any;
    }

    return componentRef?.instance as any;
  };

  if (!field._proxyInstance) {
    defineHiddenProp(
      field,
      '_proxyInstance',
      new Proxy({} as FormlyExtension, {
        get: (_, prop) => componentRefInstance()?.[prop],
        set: (_, prop, value) => (componentRefInstance()[prop] = value),
      }),
    );
  }

  return field._proxyInstance;
}

private subscribeToDraggable = (
  record: KeyValueChangeRecord<string, DatatableDraggableDirective>
): void => {
  this.unsubscribeFromDraggable(record);
  const { key, currentValue } = record;
  if (!currentValue) {
    return;
  }
  const subs = this.subscriptions.get(key) ?? [];
  let currentEvent: DragEvent;
  subs.push(
    currentValue.dragStart.subscribe(() => this.onDragStart()),
    currentValue.dragMove.subscribe(e => {
      currentEvent = e;
      this.onDragging(e, currentValue.dragModel()!, currentValue.element);
    }),
    currentValue.dragEnd.subscribe(() =>
      this.onDragEnd(currentEvent!, currentValue.dragModel()!, currentValue.element)
    )
  );
  this.subscriptions.set(key, subs);
};

// Counter to reset sort once user sort asc and desc.
  private totalSortStatesApplied = 0;
  onSort(): void {
    if (!this.column().sortable) {
      return;
    }

    this.totalSortStatesApplied++;
    let newValue = nextSortDir(this.sortType(), this.sortDir());
    // User has done both direction sort so we reset the next sort.
    if (this.enableClearingSortState() && this.totalSortStatesApplied === 3) {
      newValue = undefined;
      this.totalSortStatesApplied = 0;
    }
    this.sort.emit({
      column: this.column() as SortableTableColumnInternal<any>,
      prevValue: this.sortDir(),
      newValue
    });
  }

private _updateDisplayedPageSizeOptions() {
  if (!this._isInitialized) {
    return;
  }

  // If no page size is provided, use the first page size option or the default page size.
  if (!this.pageSize) {
    this._pageSize =
      this.pageSizeOptions.length != 0 ? this.pageSizeOptions[0] : DEFAULT_PAGE_SIZE;
  }

  this._displayedPageSizeOptions = this.pageSizeOptions.slice();

  if (this._displayedPageSizeOptions.indexOf(this.pageSize) === -1) {
    this._displayedPageSizeOptions.push(this.pageSize);
  }

  // Sort the numbers using a number-specific sort function.
  this._displayedPageSizeOptions.sort((a, b) => a - b);
  this._changeDetectorRef.markForCheck();
}

unwrap(value: string): NbAuthToken {
  let tokenClass: NbAuthTokenClass = this.fallbackClass;
  let tokenValue = '';
  let tokenOwnerStrategyName = '';
  let tokenCreatedAt: Date = null;

  const tokenPack: NbTokenPack = this.parseTokenPack(value);
  if (tokenPack) {
    tokenClass = this.getClassByName(tokenPack.name) || this.fallbackClass;
    tokenValue = tokenPack.value;
    tokenOwnerStrategyName = tokenPack.ownerStrategyName;
    tokenCreatedAt = new Date(Number(tokenPack.createdAt));
  }

  return nbAuthCreateToken(tokenClass, tokenValue, tokenOwnerStrategyName, tokenCreatedAt);

}

