toggleFocus(value: boolean) {
  const element = this.fieldAttrElements ? this.fieldAttrElements[0] : null;
  if (!element || !element.nativeElement.focus) {
    return;
  }

  const isFocused =
    !!this.document.activeElement &&
    this.fieldAttrElements.some(
      ({ nativeElement }) =>
        this.document.activeElement === nativeElement || nativeElement.contains(this.document.activeElement),
    );

  if (value && !isFocused) {
    Promise.resolve().then(() => element.nativeElement.focus());
  } else if (!value && isFocused) {
    Promise.resolve().then(() => element.nativeElement.blur());
  }
}

onVisibilityChange(): void {
  // trigger zone recalc for columns
  this.zone.run(() => {
    this.isVisible.set(true);
    this.visible.emit(true);
  });
}

runCheck(): void {
  const check = (): void => {
    // https://davidwalsh.name/offsetheight-visibility
    const { offsetHeight, offsetWidth } = this.element.nativeElement;

    if (offsetHeight && offsetWidth) {
      clearTimeout(this.timeout);
      this.onVisibilityChange();
    } else {
      clearTimeout(this.timeout);
      this.zone.runOutsideAngular(() => {
        this.timeout = window.setTimeout(() => check(), 50);
      });
    }
  };

  this.timeout = window.setTimeout(() => check());
}

private handleExpandedStateForCodeBlock(): void {
  const lines = this.getHiddenCodeLines();

  const lineNumbers = this.getHiddenCodeLineNumbers();

  const gapLines = <HTMLDivElement[]>(
    Array.from(
      this.elementRef.nativeElement.querySelectorAll(
        `.${CODE_LINE_CLASS_NAME}.${GAP_CODE_LINE_CLASS_NAME}`,
      ),
    )
  );

  for (const line of lines) {
    line.classList.remove(HIDDEN_CLASS_NAME);
  }

  for (const lineNumber of lineNumbers) {
    lineNumber.classList.remove(HIDDEN_CLASS_NAME);
  }

  for (const expandLine of gapLines) {
    expandLine.remove();
  }
}

private getBestSnippetForMatch(result: SearchResult): string {
  const hierarchy = result._snippetResult.hierarchy;
  if (hierarchy === undefined) {
    return '';
  }

  // return the most specific subheader match
  if (matched(hierarchy.lvl4)) {
    return hierarchy.lvl4!.value;
  }
  if (matched(hierarchy.lvl3)) {
    return hierarchy.lvl3!.value;
  }
  if (matched(hierarchy.lvl2)) {
    return hierarchy.lvl2!.value;
  }
  // if no subheader matched the query, fall back to just returning the most specific one
  return hierarchy.lvl3?.value ?? hierarchy.lvl2?.value ?? '';
}

export function decodeJwtPayload(payload: string): any {

  if (payload.length === 0) {
    throw new NbAuthEmptyTokenError('Cannot extract from an empty payload.');
  }

  const parts = payload.split('.');

  if (parts.length !== 3) {
    throw new NbAuthIllegalJWTTokenError(
      `The payload ${payload} is not valid JWT payload and must consist of three parts.`);
  }

  let decoded;
  try {
    decoded = urlBase64Decode(parts[1]);
  } catch (e) {
    throw new NbAuthIllegalJWTTokenError(
      `The payload ${payload} is not valid JWT payload and cannot be parsed.`);
  }

  if (!decoded) {
    throw new NbAuthIllegalJWTTokenError(
      `The payload ${payload} is not valid JWT payload and cannot be decoded.`);
  }
  return JSON.parse(decoded);
}

export function parseTriggers(triggers: string): [string, string?][] {
	const trimmedTriggers = (triggers || '').trim();

	if (trimmedTriggers.length === 0) {
		return [];
	}

	const parsedTriggers = trimmedTriggers
		.split(/\s+/)
		.map((trigger) => trigger.split(':'))
		.map((triggerPair) => (ALIASES[triggerPair[0]] || triggerPair) as [string, string?]);

	const manualTriggers = parsedTriggers.filter((triggerPair) => triggerPair.includes('manual'));

	if (manualTriggers.length > 1) {
		throw `Triggers parse error: only one manual trigger is allowed`;
	}

	if (manualTriggers.length === 1 && parsedTriggers.length > 1) {
		throw `Triggers parse error: manual trigger can't be mixed with other triggers`;
	}

	return manualTriggers.length ? [] : parsedTriggers;
}

formatValue(value: any) {
    if (value != null) {
        if (value === '-') {
            // Minus sign
            return value;
        }

        if (this.format) {
            let formatter = new Intl.NumberFormat(this.locale, this.getOptions());
            let formattedValue = formatter.format(value);

            if (this.prefix && value != this.prefix) {
                formattedValue = this.prefix + formattedValue;
            }

            if (this.suffix && value != this.suffix) {
                formattedValue = formattedValue + this.suffix;
            }

            return formattedValue;
        }

        return value.toString();
    }

    return '';
}

export function parseTriggers(triggers?: string, aliases: any = DEFAULT_ALIASES): Trigger[] {
  const trimmedTriggers = (triggers || '').trim();

  if (trimmedTriggers.length === 0) {
    return [];
  }

  const parsedTriggers = trimmedTriggers
    .split(/\s+/)
    .map((trigger: string) => trigger.split(':'))
    .map((triggerPair: string[]) => {
      const alias = aliases[triggerPair[0]] || triggerPair;

      return new Trigger(alias[0], alias[1]);
    });

  const manualTriggers = parsedTriggers.filter((triggerPair: Trigger) =>
    triggerPair.isManual()
  );

  if (manualTriggers.length > 1) {
    throw new Error('Triggers parse error: only one manual trigger is allowed');
  }

  if (manualTriggers.length === 1 && parsedTriggers.length > 1) {
    throw new Error('Triggers parse error: manual trigger can\'t be mixed with other triggers');
  }

  return parsedTriggers;
}

checkPosition({ scrollHeight, scrollTop, clientHeight }: NbScrollableContainerDimensions) {
  const initialCheck = this.lastScrollPosition == null;
  const manualCheck = this.lastScrollPosition === scrollTop;
  const scrollUp = scrollTop < this.lastScrollPosition;
  const scrollDown = scrollTop > this.lastScrollPosition;
  const distanceToBottom = scrollHeight - scrollTop - clientHeight;

  if ((initialCheck || manualCheck || scrollDown) && distanceToBottom <= this.threshold) {
    this.bottomThreshold$.next();
  }

  if ((initialCheck || scrollUp) && scrollTop <= this.threshold) {
    this.topThreshold$.next();
  }

  this.lastScrollPosition = scrollTop;
}

export class Value implements firebase.remoteConfig.Value {
  asBoolean() {
    return ['1', 'true', 't', 'y', 'yes', 'on'].includes(this._value.toLowerCase());
  }

  asString() {
    return this._value;
  }

  asNumber() {
    return Number(this._value) || 0;
  }

  getSource() {
    return this._source;
  }

  constructor(public _source: firebase.remoteConfig.ValueSource, public _value: string) {
  }
}

