export class Parameter extends Value {
  constructor(public key: string, public fetchTimeMillis: number, source: firebase.remoteConfig.ValueSource, value: string) {
    super(source, value);
  }
}

function extractArgsFromSelectorsDictionary(
  selectorsDictionary: Record<string, Selector<unknown, unknown>>
): [
  ...selectors: Selector<unknown, unknown>[],
  projector: (...selectorResults: unknown[]) => unknown,
] {
  const selectors = Object.values(selectorsDictionary);
  const resultKeys = Object.keys(selectorsDictionary);
  const projector = (...selectorResults: unknown[]) =>
    resultKeys.reduce(
      (result, key, index) => ({
        ...result,
        [key]: selectorResults[index],
      }),
      {}
    );

  return [...selectors, projector];
}

private setSortedExtensions(extensionOptions: ExtensionOption[]) {
  // insert new extensions, grouped by priority
  extensionOptions.forEach((extensionOption) => {
    const priority = extensionOption.priority ?? 1;
    this.extensionsByPriority[priority] = {
      ...this.extensionsByPriority[priority],
      [extensionOption.name]: extensionOption.extension,
    };
  });
  // flatten extensions object with sorted keys
  this.extensions = Object.keys(this.extensionsByPriority)
    .map(Number)
    .sort((a, b) => a - b)
    .reduce(
      (acc, prio) => ({
        ...acc,
        ...this.extensionsByPriority[prio],
      }),
      {},
    );
}

parseDurationToMilliseconds(durationString: string): number | undefined {
    const transitionTimeRegex = /([\d\.]+)(ms|s)\b/g;
    let totalMilliseconds = 0;
    let match;
    while ((match = transitionTimeRegex.exec(durationString)) !== null) {
        const value = parseFloat(match[1]);
        const unit = match[2];
        if (unit === 'ms') {
            totalMilliseconds += value;
        } else if (unit === 's') {
            totalMilliseconds += value * 1000;
        }
    }
    if (totalMilliseconds === 0) {
        return undefined;
    }
    return totalMilliseconds;
}

shiftL(begin: number, end: number) {
    let i, j;

    if (begin < 0) {
        return;
    }

    for (i = begin, j = this.seekNext(end); i < (this.len as number); i++) {
        if (this.tests[i]) {
            if (j < (this.len as number) && this.tests[i].test(this.buffer[j])) {
                this.buffer[i] = this.buffer[j];
                this.buffer[j] = this.getPlaceholder(j);
            } else {
                break;
            }

            j = this.seekNext(j);
        }
    }
    this.writeBuffer();
    this.caret(Math.max(this.firstNonMaskPos as number, begin));
}
